(window.webpackJsonp=window.webpackJsonp||[]).push([[258],{885:function(n,e){n.exports="\x3c!-- \ntitle: 01-入门\nsort: \n--\x3e \n\n> HelloWorld\n\n```js\nlet electron = require('electron')\n\nelectron.app.on('ready', ()=>{\n    let mainWindow = new electron.BrowserWindow({width: 960,height: 720})\n    mainWindow.loadFile('index.html')\n    mainWindow.on('closed',()=>{\n        mainWindow = null\n    })\n})\n\nyarn init --yes\nelectron .\n```\n\n## First\n\n![electron](https://gitee.com/nmdfzf404/Image-hosting/raw/master/2020/20201214222757.png)\n\n> `main.js`\n\n```js\nconst electron = require('electron')\n\nconst app = electron.app\nconst BrowserWindow = electron.BrowserWindow\n\nlet mainWindow = null\n\napp.on('ready', () => {\n    mainWindow = new BrowserWindow({\n        width: 960,\n        height: 720,\n        webPreferences: { nodeIntegration: true }\n    })\n    mainWindow.loadFile('index.html')\n    mainWindow.on('closed', () => {\n        mainWindow = null\n    })\n})\n```\n\n> `index.html`\n\n```html\n<html lang=\"en\">\n\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Hello Electron</title>\n</head>\n\n<body>\n  <h2>Hello Electron</h2>\n  <button id=\"btn\">Log in</button>\n  <div class=\"info\"></div>\n  <script src=\"render/index.js\"><\/script>\n</body>\n\n</html>\n```\n\n> `render/index.js`\n\n```js\n// 文件系统交互\nconst fs = require('fs');\n\nwindow.onload = () => {\n    let btn = this.document.getElementById('btn');\n    let info = this.document.getElementsByClassName('info');\n    btn.onclick = () => {\n        fs.readFile('info.txt', (err, data) => {\n            info[0].innerHTML = `<p>${data}</p>`\n        })\n    }\n}\n```\n\n> `info.txt`\n\n```\nUser: fzf404\n```\n\n![image-20201214222625781](https://gitee.com/nmdfzf404/Image-hosting/raw/master/2020/20201214222625.png)"}}]);